#include<bits/stdc++.h>
using namespace std;
#define ll long long
#define dbg(x) cerr<<#x" = "<<(x)<<'\n';
const int N=10005,M=50005,inf=0x3f3f3f3f;
struct node
{
	int u,v,w;
	bool operator<(const node other) const
	{
		return w>other.w;
	}
} a[M];
struct Node
{
	int v,w;
};
int fa[N],n,m,dep[N],f[N][25],mn[N][25],vis[N];
vector<Node> g[N];
int find(int x)
{
	if(fa[x]==x) return x;
	return fa[x]=find(fa[x]);
}
void dfs(int u,int ff,int w,int tmp)
{
	vis[u]=tmp;
	mn[u][0]=w;
	dep[u]=dep[ff]+1;
	f[u][0]=ff;
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i].v;
		if(v==ff) continue;
		dfs(v,u,g[u][i].w,tmp);
	}
}
int lca(int x,int y)
{
	if(dep[y]<dep[x]) swap(x,y);
	int k=log2(dep[y])+1,mnn=inf;
	for(int i=k;i>=0;i--)
	{
		if((dep[y]-(1<<i))>=dep[x])
		{
			mnn=min(mnn,mn[y][i]);
			y=f[y][i];
		}
	}
	if(x==y) return mnn;
	for(int i=k;i>=0;i--)
	{
		if(f[x][i]&&f[x][i]!=f[y][i])
		{
			mnn=min(mnn,mn[y][i]);
			mnn=min(mnn,mn[x][i]);
            x=f[x][i];
			y=f[y][i];

		}
	}
	return min(mnn,min(mn[x][0],mn[y][0]));
}
int main()
{
	ios::sync_with_stdio(false);
	cin.tie(0),cout.tie(0);
	cin>>n>>m;
	for(int i=1;i<=n;i++) fa[i]=i;
	for(int i=1;i<=m;i++)
	{
		int u,v,w;
		cin>>u>>v>>w;
		a[i]=node{u,v,w};
	}
	sort(a+1,a+1+m);
	for(int i=1;i<=m;i++)
	{
		int u=a[i].u,v=a[i].v,w=a[i].w;
//		cout<<u<<"  --  "<<v<<"  : "<<w<<"\n";
		int fu=find(u),fv=find(v);
		if(fu==fv) continue;
//		cout<<u<<"  --  "<<v<<"  w : "<<w<<"\n";
//		cout<<"YES\n";
		fa[fu]=fv;
		g[u].push_back(Node{v,w});
		g[v].push_back(Node{u,w});
	}
	int cnt=0;
	for(int i=1;i<=n;i++)
	{
		if(!vis[i])
		{
			cnt++;
			dfs(i,0,0,cnt);
		}
	}
	for(int i=1;i<=log2(n);i++)
	{
		for(int j=1;j<=n;j++)
		{
			f[j][i]=f[f[j][i-1]][i-1];
			mn[j][i]=min(mn[j][i-1],mn[f[j][i-1]][i-1]);
		}
	}
	int q;
	cin>>q;
	while(q--)
	{
		int u,v;
		cin>>u>>v;
		if(vis[u]!=vis[v]) cout<<-1<<"\n";
		else cout<<lca(u,v)<<"\n";
	}
	return 0;
}
